class Solution {
    public long minEnd(int n, int x) {
        int[] nums = new int[n];
        int result = Long.MAX_VALUE;
        for (int i = n - 1; i >= 0; i--) {
            nums[i] = (x & (1L << i));
            result = Math.min(result, nums[i]);
        }
        return result;
    }
}
